<div class="page-title"><h2>Reportes por rango de fechas</h2></div><div class="card"><form method="get" action="/reports" class="form inline-form"><label>Tipo<select name="type"><option value="sales" <?= $type==='sales'?'selected':'' ?>>Ventas</option><option value="purchases" <?= $type==='purchases'?'selected':'' ?>>Compras</option><option value="expenses" <?= $type==='expenses'?'selected':'' ?>>Gastos</option><option value="inventory" <?= $type==='inventory'?'selected':'' ?>>Inventario valorizado</option><option value="movements" <?= $type==='movements'?'selected':'' ?>>Movimientos de inventario</option></select></label><label>Desde<input type="date" name="from" value="<?= e($from) ?>"></label><label>Hasta<input type="date" name="to" value="<?= e($to) ?>"></label><button class="btn">Consultar</button></form></div><div class="card"><?php if($type==='inventory'): ?><table class="table"><thead><tr><th>Producto</th><th>Categoría</th><th>Stock</th><th>Costo</th><th>Total</th></tr></thead><tbody><?php foreach($data as $row): ?><tr><td><?= e($row['name']) ?></td><td><?= e($row['category_name']) ?></td><td><?= money($row['stock']) ?></td><td><?= money($row['cost']) ?></td><td><?= money($row['inventory_total']) ?></td></tr><?php endforeach; ?></tbody></table><?php elseif($type==='movements'): ?><table class="table"><thead><tr><th>Fecha</th><th>Producto</th><th>Almacén</th><th>Tipo</th><th>Cantidad</th><th>Referencia</th></tr></thead><tbody><?php foreach($data as $row): ?><tr><td><?= e($row['created_at']) ?></td><td><?= e(product_display_name($row['product_name'] ?? '', $row['category_name'] ?? '')) ?></td><td><?= e($row['warehouse_name']) ?></td><td><?= e($row['movement_type']) ?></td><td><?= money($row['quantity']) ?></td><td><?= e($row['reference']) ?></td></tr><?php endforeach; ?></tbody></table><?php else: ?><table class="table"><thead><tr><th>Fecha</th><th>Referencia</th><th>Tercero</th><th>Moneda</th><th>Tasa</th><th>Original</th><th>Convertido</th></tr></thead><tbody><?php foreach($data as $row): ?><tr><td><?= e($row['invoice_date'] ?? $row['purchase_date'] ?? $row['expense_date'] ?? '') ?></td><td><?= e($row['invoice_number'] ?? $row['doc_number'] ?? $row['reference'] ?? '') ?></td><td><?= e($row['client_name'] ?? $row['supplier_name'] ?? $row['category_name'] ?? '') ?></td><td><?= e($row['currency_code'] ?? '') ?></td><td><?= money($row['exchange_rate'] ?? 0) ?></td><td><?= money($row['total_original'] ?? $row['amount_original'] ?? 0) ?></td><td><?= money($row['total_converted'] ?? $row['amount_converted'] ?? 0) ?></td></tr><?php endforeach; ?></tbody></table><?php endif; ?></div>
